import {
  ChangeDetectionStrategy,
  Component,
  forwardRef,
  InjectionToken,
  model,
  ViewEncapsulation,
} from '@angular/core';

/**
 * Tool — collapsible card for an AI SDK tool invocation. Mirrors React
 * `Tool`. Owns open/close state shared with `ToolHeader` and `ToolContent`.
 *
 * The host surface mirrors React `Tool` (`not-prose mb-4 w-full
 * rounded-md border`) — not `gn-card`, because the React blueprint uses
 * a tighter border + radius than Card. The header badge dogfoods
 * `gn-badge` from `@gremorie/ng-display`.
 */
export interface ToolHostState {
  isOpen: () => boolean;
  setOpen(open: boolean): void;
  toggle(): void;
}

export const TOOL = new InjectionToken<ToolHostState>('ToolHostState');

@Component({
  selector: 'tool',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'not-prose mb-4 block w-full rounded-md border',
    '[attr.data-state]': 'open() ? "open" : "closed"',
  },
  providers: [{ provide: TOOL, useExisting: forwardRef(() => Tool) }],
})
export class Tool implements ToolHostState {
  readonly open = model<boolean>(false);

  readonly isOpen = () => this.open();

  setOpen(open: boolean): void {
    this.open.set(open);
  }

  toggle(): void {
    this.open.update((v) => !v);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { TOOL } from './tool';

/**
 * ToolContent — collapsible body. Mirrors React `ToolContent`.
 */
@Component({
  selector: 'tool-content',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (open()) {
      <div
        class="text-popover-foreground outline-none animate-in slide-in-from-top-2"
      >
        <ng-content />
      </div>
    }
  `,
})
export class ToolContent {
  private readonly host = inject(TOOL);
  protected readonly open = computed(() => this.host.isOpen());
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { CodeBlock } from '../code-block/code-block';

/**
 * ToolInput — labelled JSON block showing the tool's parameters. Mirrors
 * React `ToolInput`, which renders its content via the shared `CodeBlock`
 * (Shiki-highlighted). This Angular version dogfoods the ng-ai
 * `<code-block>` primitive directly with `language="json"`.
 */
@Component({
  selector: 'tool-input',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CodeBlock],
  template: `
    <h4
      class="font-medium text-muted-foreground text-xs uppercase tracking-wide"
    >
      Parameters
    </h4>
    <div class="rounded-md bg-muted/50 overflow-auto">
      <code-block [code]="formatted()" language="json" />
    </div>
  `,
  host: {
    class: 'space-y-2 overflow-hidden p-4 block',
  },
})
export class ToolInput {
  readonly value = input<unknown>(null, { alias: 'input' });

  protected readonly formatted = computed(() => {
    try {
      return JSON.stringify(this.value(), null, 2);
    } catch {
      return String(this.value());
    }
  });
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { cn } from '@gremorie/ng-core';
import { CodeBlock } from '../code-block/code-block';

/**
 * ToolOutput — labelled body showing either the result or an error. Mirrors
 * React `ToolOutput`. Auto-formats object output as JSON; string output is
 * rendered via the same code-block highlighter (json language) so the
 * surface stays consistent with rx-ai which routes both through CodeBlock.
 *
 * Errors are rendered as plain text inside a destructive-tinted container
 * (no highlight) since they are not structured data.
 *
 * When both inputs are empty, renders nothing (matches React behavior).
 */
@Component({
  selector: 'tool-output',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CodeBlock],
  template: `
    @if (visible()) {
      <h4
        class="font-medium text-muted-foreground text-xs uppercase tracking-wide"
      >
        {{ heading() }}
      </h4>
      <div [class]="bodyClass()">
        @if (errorText()) {
          <div class="p-4 text-xs">{{ errorText() }}</div>
        }
        @if (hasOutput()) {
          <code-block [code]="formatted()" language="json" />
        }
      </div>
    }
  `,
  host: {
    '[class]': 'hostClass()',
  },
})
export class ToolOutput {
  readonly output = input<unknown>(null);
  readonly errorText = input<string | null | undefined>(null);

  protected readonly hasOutput = computed(() => {
    const o = this.output();
    return o !== null && o !== undefined && o !== '';
  });

  protected readonly visible = computed(
    () => this.hasOutput() || !!this.errorText(),
  );

  protected readonly heading = computed(() =>
    this.errorText() ? 'Error' : 'Result',
  );

  protected readonly hostClass = computed(() =>
    cn('space-y-2 p-4', !this.visible() && 'hidden'),
  );

  protected readonly bodyClass = computed(() =>
    cn(
      'overflow-x-auto rounded-md text-xs [&_table]:w-full',
      this.errorText()
        ? 'bg-destructive/10 text-destructive'
        : 'bg-muted/50 text-foreground',
    ),
  );

  protected readonly formatted = computed(() => {
    const o = this.output();
    if (o === null || o === undefined) return '';
    if (typeof o === 'string') return o;
    try {
      return JSON.stringify(o, null, 2);
    } catch {
      return String(o);
    }
  });
}

export { Tool, TOOL } from './tool';
export type { ToolHostState } from './tool';
export { ToolHeader } from './tool-header';
export { ToolContent } from './tool-content';
export { ToolInput } from './tool-input';
export { ToolOutput } from './tool-output';
export type { ToolState } from './tool.types';
